function generateFibonacciList(num) {
  if (isNaN(num) || num <= 0 0) {
    console.log("Invalid input: Please enter a positive integer.");
    return;
  }

  let fibList = [1, 1];
  let nextNum = 2;

  while (nextNum <= num) {
    fibList.push(nextNum);
    nextNum = fibList[fibList.length - 1] + fibList[fibList.length - 2];
  }

  console.log("Fibonacci sequence up to " + num + ":");
  console.log(fibList.join(", "));
}

